```plantuml
@startuml
class Person {
    id: Long
    firstName: String
    lastName: String
    telNr: String
}

class Booking {
    id: Long
    person: Person
    trip: Trip
}

class Trip {
    id: Long
    destination: Destination
    bus: Bus
}

class Bus {
    id: Long
    seats: int
}

class Destination {
    id: Long
    street: String
    streetNo: int
    place: String
    zip: int
}

Person "1" --> "*" Booking : bucht Reise (Trip)
Booking "1" --> "*" Trip : hat Buchungen
Trip "1" --> "1" Bus : Reise wird mit Bus durchgeführt
Trip "1" --> "*" Destination : Reise geht nach

@enduml
```
